  background: var(--accent); color: #fff;
  border: none; border-radius: var(--r-sm);
  padding: 9px 20px; font-size: 14px; font-weight: 700;
  margin-left: 8px;
  transition: background .15s;
  white-space: nowrap;
}
.btn-pedir:hover { background: var(--accent-h); }
.hamburger {
  display: none; background: none; border: none;
  color: var(--fg); padding: 6px; margin-left: 12px;
}

/* ── MOBILE MENU ── */
.mob-menu {
  display: none; position: fixed; inset: 0; z-index: 200;
  background: var(--bg);
  flex-direction: column; padding: 24px;
}
.mob-menu.open { display: flex; }
.mob-menu-head {
  display: flex; align-items: center;
  justify-content: space-between; margin-bottom: 40px;
}
.mob-links { list-style: none; display: flex; flex-direction: column; gap: 0; }
.mob-links a {
  display: block; font-size: 26px; font-weight: 800;
  padding: 14px 0; border-bottom: 1px solid var(--border);
  transition: color .15s;
}
